  ('dietitian-moex-04714', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關糖尿病腎病變病人醫學營養治療，下列何者較適當？', '["在延緩腎功能喪失速度上，血糖控制好比降低蛋白質攝取量更重要", "出現水腫低血鈉時，飲食應增加鹽的攝取以改善低血鈉", "豆腐等植物性蛋白質會增加腎臟負擔，病人應避免食用", "血糖控制良好時容易發生低血鉀，飲食要注意補充鉀"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04715', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '醫師轉介本月開始腹膜透析的張先生至營養門診，下列何項飲食建議最不適當？', '["需降低醣類攝取", "需降低鉀的攝取", "需降低磷的攝取", "需降低飽和脂肪的攝取"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04716', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列何者為食物中容易增加腎臟溶質負荷（soluteload）最主要的成分？', '["纖維質", "蛋白質", "醣類", "脂質"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04717', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '林女士 68歲，血液生化值如下（括弧內數值為正常值範圍）：BUN58（7～20）mg/dL、 creatinine3.7（0.5～1.3）mg/dL、GFR：23mL/min、potassium4.2（3.5～5.5）mEq/L、phosphorus', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04718', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '6（2.5～4.8）mg/dL、Hb9.0（12～14）g/dL，醫師診斷她為慢性腎衰竭。根據K/DOQIguideline， 下列何項飲食建議不適當？', '["每日蛋白質建議量為0.6g/kg", "如果達不到足夠熱量的攝取，蛋白質攝取量可以增加到每日0.75g/kg", "每日蛋白質攝取量0.6g/kg時，其中至少80%需來自highbiologicalvalueprotein", "每日蛋白質攝取量0.75g/kg時，其中至少50%需來自highbiologicalvalueprotein"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04719', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '王女士62歲、身高158公分、體重78公斤，罹患高血壓、高脂血症多年並無按時就診服藥， 平日參加土風舞社團作為運動，但最近常感到疲倦、呼吸不順且下肢水腫，這次因參加土風 舞活動不到十分鐘後突然暈倒，送醫後才被診斷為心衰竭。在此階段的營養需求與評估項目， 下列何者正確？', '["減少餐次並增加當餐份量有助於心衰竭病人減重", "Thiamin補充有助於改善左心室射出分率", "每日容許增加的水腫體重為2.5公斤", "可檢測到病人血中coenzymeQ10濃度較高的情況"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04720', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '陳女士62歲，因嚴重的心肌病變將進行心臟移植，入院評估時身高162公分、理想體重58 公斤。因食慾變差近兩個月體重從45公斤下降至40公斤，醫師認為陳女士的體重太輕，若 想降低術後的死亡率，則進行手術的最低建議體重為何？', '["53.6公斤", "46.4公斤", "42.2公斤", "48.5公斤"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04721', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '承上題，陳女士於心臟移植手術後出院，六個月後回診的健康檢查顯示 T-score＜-1.0，下列 建議何者不適當？', '["給予抗骨流失藥物，如雙磷酸鹽類", "給予負重運動鍛鍊", "每日鈣質建議量為800～1,000mg", "雌激素補充"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
